 {"id":"bd-mblr.1.4.1","title":"Coverage and realism SLO threshold policy","description":"Define enforceable thresholds for coverage and no-mock critical-path evidence, including staged rollout levels. Output: explicit gate policy with hard fail criteria and temporary exceptions protocol.","design":"Represent thresholds and exceptions as structured config so CI jobs can enforce without custom parsing.","acceptance_criteria":"- Threshold table exists for baseline and target phases, with clear promotion criteria between phases.
- No-mock critical-path evidence requirement is machine-checkable.
- Temporary exceptions require explicit owner, justification, and sunset date.","notes":"Do not encode policy in scattered scripts; keep a single authoritative source consumed by gate jobs.","status":"closed","priority":1,"issue_type":"task","created_at":"2026-02-12T23:37:52.025549254Z","created_by":"ubuntu","updated_at":"2026-02-13T01:04:36.844514607Z","closed_at":"2026-02-13T01:04:36.844494780Z","close_reason":"Created docs/coverage-slo-policy.md with thresholds (70% line hard fail, 80% target), per-crate requirements, realism tier requirements for critical paths, staged rollout plan, and exception protocol.","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.1.4.1","depends_on_id":"bd-mblr.1.1.2","type":"blocks","created_at":"2026-02-12T23:38:31.086244562Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.1.4.1","depends_on_id":"bd-mblr.1.2.2","type":"blocks","created_at":"2026-02-12T23:38:31.344794465Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.1.4.1","depends_on_id":"bd-mblr.1.3.2","type":"blocks","created_at":"2026-02-12T23:38:31.593312092Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.1.4.1","depends_on_id":"bd-mblr.1.4","type":"parent-child","created_at":"2026-02-12T23:37:52.025549254Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.2","title":"No-Mock Real-Backend Test Expansion","description":"Expand test suites so critical invariants are validated against real components (real pager/wal/mvcc/btree/vfs paths), not only mocks/fakes or in-memory substitutes.","design":"Retain mock tests for contracts, but require real-stack behavior tests for invariants.","acceptance_criteria":"Critical paths validated by at least one real-backend non-mock test each; fault-injection recovery paths verified; file-backed lifecycle tests added.","notes":"Deferred intentionally for queue hygiene: this bead is a container/coordination umbrella, not a direct implementation lane. Work proceeds through its child tasks; reopen/close this bead during milestone rollup and completion review.","status":"deferred","priority":1,"issue_type":"epic","created_at":"2026-02-12T23:23:16.819632916Z","created_by":"ubuntu","updated_at":"2026-02-13T00:51:03.694818719Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2","depends_on_id":"bd-mblr","type":"parent-child","created_at":"2026-02-12T23:23:16.819632916Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2","depends_on_id":"bd-mblr.1","type":"blocks","created_at":"2026-02-12T23:25:05.852519634Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":1340,"issue_id":"bd-mblr.2","author":"Dicklesworthstone","text":"Detailed scope: prioritize behavior-invariant tests over interface-contract tests. Existing mock exports (pager and btree traits) remain useful for unit isolation, but cannot be sole evidence for correctness of integrated persistence, concurrency, and recovery flows.","created_at":"2026-02-12T23:26:03Z"}]}
