 {"id":"bd-mblr.2.1.1","title":"Real-backend composition harness","description":"Create composition tests that exercise pager/WAL/MVCC/B-tree over real file-backed VFS paths, not trait mocks. Output: harness + deterministic assertions for integrated behavior.","design":"Use small composable fixtures for files, page sizes, and transaction windows so higher-level tests can vary one factor at a time.","acceptance_criteria":"- Harness can instantiate real backend stack without trait mocks for deterministic scenarios.
- Harness supports controlled setup/teardown, seeded workloads, and state inspection checkpoints.
- At least one end-to-end smoke scenario per major storage subsystem passes through harness.","notes":"Treat this as foundational plumbing for bd-mblr.2.1.2, 2.2.*, and 2.3.*.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-12T23:37:52.283916314Z","created_by":"ubuntu","updated_at":"2026-02-13T00:04:43.421158941Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.1.1","depends_on_id":"bd-mblr.1.3.2","type":"blocks","created_at":"2026-02-12T23:38:31.847723219Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.1.1","depends_on_id":"bd-mblr.2.1","type":"parent-child","created_at":"2026-02-12T23:37:52.283916314Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.2.1.2","title":"Conflict/recovery assertions on integrated backend","description":"Add integrated tests that force page-level conflicts, rollback/retry paths, and recovery invariants on real backend components. Output: high-signal assertions proving correct conflict semantics end-to-end.","design":"Model conflict scenarios as declarative sequences (actor, page set, operation, expected visibility) to maximize reproducibility.","acceptance_criteria":"- Tests induce page-level conflicts and validate retry/rollback/recovery correctness with deterministic outcomes.
- Assertions verify no regression to serialized single-writer behavior unless explicitly configured.
- Failure artifacts include transaction timeline and page/version-chain evidence for root-cause diagnosis.","notes":"Keep coverage focused on MVCC conflict semantics and recovery invariants, not synthetic lock escalation behavior.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-12T23:37:52.540175750Z","created_by":"ubuntu","updated_at":"2026-02-13T00:04:43.486630038Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.2.1.2","depends_on_id":"bd-mblr.2.1","type":"parent-child","created_at":"2026-02-12T23:37:52.540175750Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.2.1.2","depends_on_id":"bd-mblr.2.1.1","type":"blocks","created_at":"2026-02-12T23:38:32.101383110Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
